CREATE SCHEMA IF NOT EXISTS dw;

BEGIN;

-- ────────────────────────────────────────────────────────────
-- DDL — Dimensions & Table de faits
-- ────────────────────────────────────────────────────────────

DROP TABLE IF EXISTS dw.dim_date CASCADE;
CREATE TABLE IF NOT EXISTS dw.dim_date (
    date_id      INT PRIMARY KEY,
    full_date    DATE NOT NULL,
    year         SMALLINT,
    quarter      SMALLINT,
    month        SMALLINT,
    month_name   VARCHAR(20),
    week         SMALLINT,
    day_of_month SMALLINT,
    day_of_week  SMALLINT,
    is_weekend   BOOLEAN
);
DROP TABLE IF EXISTS dw.dim_seller CASCADE;
CREATE TABLE IF NOT EXISTS dw.dim_seller (
    seller_id    SERIAL PRIMARY KEY,
    seller_code  VARCHAR(10) NOT NULL UNIQUE,
    first_name   VARCHAR(60),
    last_name    VARCHAR(60),
    email        VARCHAR(120),
    salary       NUMERIC(12,2),
    hire_date    DATE,
    home_country VARCHAR(60),
    home_region  VARCHAR(80),
    home_city    VARCHAR(80),
    manager_code VARCHAR(10)
);
DROP TABLE IF EXISTS dw.dim_customer CASCADE;
CREATE TABLE IF NOT EXISTS dw.dim_customer (
    customer_id   SERIAL PRIMARY KEY,
    customer_code VARCHAR(10) NOT NULL UNIQUE,
    customer_name VARCHAR(150),
    sector        VARCHAR(50),
    country       VARCHAR(60),
    region_name   VARCHAR(80),
    city          VARCHAR(80),
    postal_code   VARCHAR(20),
    created_at    DATE
);
DROP TABLE IF EXISTS dw.dim_product CASCADE;
CREATE TABLE IF NOT EXISTS dw.dim_product (
    product_id    SERIAL PRIMARY KEY,
    product_code  VARCHAR(10) NOT NULL UNIQUE,
    product_name  VARCHAR(120),
    category_name VARCHAR(60),
    range_name    VARCHAR(50),
    list_price    NUMERIC(12,2),
    active_flag   SMALLINT,
    launch_date   DATE
);
DROP TABLE IF EXISTS dw.fact_sales_activity CASCADE;
CREATE TABLE IF NOT EXISTS dw.fact_sales_activity (
    fact_id          SERIAL PRIMARY KEY,
    date_id          INT REFERENCES dw.dim_date(date_id),
    seller_id        INT REFERENCES dw.dim_seller(seller_id),
    customer_id      INT REFERENCES dw.dim_customer(customer_id),
    product_id       INT REFERENCES dw.dim_product(product_id),
    order_id         VARCHAR(20),
    order_status     VARCHAR(20),
    quantity         NUMERIC(10,2),
    unit_price       NUMERIC(12,2),
    discount_pct     NUMERIC(5,2),
    net_sales_amount NUMERIC(14,2),
    promise_qty      NUMERIC(10,2),
    expected_amount  NUMERIC(14,2),
    promise_status   VARCHAR(30),
    probability_pct  NUMERIC(5,2),
    km_travelled     NUMERIC(10,2),
    travel_expense   NUMERIC(10,2),
    road_toll        NUMERIC(10,2),
    fuel_liters      NUMERIC(10,2),
    fuel_cost        NUMERIC(10,2),
    total_field_cost NUMERIC(12,2)
);

